sub log_event {
    my ($level, $message) = @_;
    my $timestamp = localtime();
    my $log_entry = "[$timestamp] [$level] $message\n";

    if (open(my $fh, '>>', $LOG_FILE)) {
        print $fh $log_entry;
        close($fh);
    }

    if ($level eq 'ERROR' || $level eq 'SECURITY') {
        warn $log_entry;
    }
}

